module adder_8bit
(
    input [7:0] a,
    input [7:0] b,
    input cin,
    output [7:0] sum,
    output cout
);
    // YOUR CODE HERE
    wire [7:0] sum_wire;
    wire [7:0] cout_wire;
    assign sum_wire[0] = a[0] ^ b[0] ^ cin;
    assign cout_wire[0] = (a[0] & b[0]) | (a[0] & cin) | (b[0] & cin);
    assign sum_wire[1] = a[1] ^ b[1] ^ cout_wire[0];
    assign cout_wire[1] = (a[1] & b[1]) | (a[1] & cout_wire[0]) | (b[1] & cout_wire[0]);
    assign sum_wire[2] = a[2] ^ b[2] ^ cout_wire[1];
    assign cout_wire[2] = (a[2] & b[2]) | (a[2] & cout_wire[1]) | (b[2] & cout_wire[1]);
    assign sum_wire[3] = a[3] ^ b[3] ^ cout_wire[2];
    assign cout_wire[3] = (a[3] & b[3]) | (a[3] & cout_wire[2]) | (b[3] & cout_wire[2]);
    assign sum_wire[4] = a[4] ^ b[4] ^ cout_wire[3];
    assign cout_wire[4] = (a[4] & b[4]) | (a[4] & cout_wire[3]) | (b[4] & cout_wire[3]);
    assign sum_wire[5] = a[5] ^ b[5] ^ cout_wire[4];
    assign cout_wire[5] = (a[5] & b[5]) | (a[5] & cout_wire[4]) | (b[5] & cout_wire[4]);
    assign sum_wire[6] = a[6] ^ b[6] ^ cout_wire[5];
    assign cout_wire[6] = (a[6] & b[6]) | (a[6] & cout_wire[5]) | (b[6] & cout_wire[5]);
    assign sum_wire[7] = a[7] ^ b[7] ^ cout_wire[6];
    assign cout_wire[7] = (a[7] & b[7]) | (a[7] & cout_wire[6]) | (b[7] & cout_wire[6]);
    assign sum = sum_wire;
    assign cout = cout_wire[7];

endmodule
